INSERT INTO MASKING_POLICY_TEMPLATES SELECT 'DATE_YEAR_ONLY','DATE','Shows only the year, masks month and day','CASE WHEN IS_ROLE_IN_SESSION(''<AUTHORIZED_ROLE>'') THEN val ELSE DATE_FROM_PARTS(YEAR(val), 1, 1) END','2026-01-01',True WHERE NOT EXISTS (SELECT 1 FROM MASKING_POLICY_TEMPLATES WHERE TEMPLATE_NAME='DATE_YEAR_ONLY' AND DATA_TYPE='DATE');
INSERT INTO MASKING_POLICY_TEMPLATES SELECT 'FULL_MASK','NUMBER','Replaces numbers with -1 for unauthorized roles','CASE WHEN IS_ROLE_IN_SESSION(''<AUTHORIZED_ROLE>'') THEN val ELSE -1 END','-1',True WHERE NOT EXISTS (SELECT 1 FROM MASKING_POLICY_TEMPLATES WHERE TEMPLATE_NAME='FULL_MASK' AND DATA_TYPE='NUMBER');
INSERT INTO MASKING_POLICY_TEMPLATES SELECT 'FULL_MASK','STRING','Fully masks string values for unauthorized roles','CASE WHEN IS_ROLE_IN_SESSION(''<AUTHORIZED_ROLE>'') THEN val ELSE ''***MASKED***'' END','***MASKED***',True WHERE NOT EXISTS (SELECT 1 FROM MASKING_POLICY_TEMPLATES WHERE TEMPLATE_NAME='FULL_MASK' AND DATA_TYPE='STRING');
INSERT INTO MASKING_POLICY_TEMPLATES SELECT 'FULL_MASK','VARIANT','Replaces variant with empty object for unauthorized roles','CASE WHEN IS_ROLE_IN_SESSION(''<AUTHORIZED_ROLE>'') THEN val ELSE TO_VARIANT(''MASKED'') END','MASKED',True WHERE NOT EXISTS (SELECT 1 FROM MASKING_POLICY_TEMPLATES WHERE TEMPLATE_NAME='FULL_MASK' AND DATA_TYPE='VARIANT');
INSERT INTO MASKING_POLICY_TEMPLATES SELECT 'LAST_4_DIGITS','STRING','Shows only last 4 characters','CASE WHEN IS_ROLE_IN_SESSION(''<AUTHORIZED_ROLE>'') THEN val ELSE CONCAT(''****'', RIGHT(val, 4)) END','****1234',True WHERE NOT EXISTS (SELECT 1 FROM MASKING_POLICY_TEMPLATES WHERE TEMPLATE_NAME='LAST_4_DIGITS' AND DATA_TYPE='STRING');
INSERT INTO MASKING_POLICY_TEMPLATES SELECT 'NULL_MASK','NUMBER','Returns NULL for unauthorized roles','CASE WHEN IS_ROLE_IN_SESSION(''<AUTHORIZED_ROLE>'') THEN val ELSE NULL END','NULL',True WHERE NOT EXISTS (SELECT 1 FROM MASKING_POLICY_TEMPLATES WHERE TEMPLATE_NAME='NULL_MASK' AND DATA_TYPE='NUMBER');
INSERT INTO MASKING_POLICY_TEMPLATES SELECT 'NULL_MASK','STRING','Returns NULL for unauthorized roles','CASE WHEN IS_ROLE_IN_SESSION(''<AUTHORIZED_ROLE>'') THEN val ELSE NULL END','NULL',True WHERE NOT EXISTS (SELECT 1 FROM MASKING_POLICY_TEMPLATES WHERE TEMPLATE_NAME='NULL_MASK' AND DATA_TYPE='STRING');
INSERT INTO MASKING_POLICY_TEMPLATES SELECT 'NULL_MASK','TIMESTAMP_LTZ','Returns NULL for unauthorized roles','CASE WHEN IS_ROLE_IN_SESSION(''<AUTHORIZED_ROLE>'') THEN val ELSE NULL END','NULL',True WHERE NOT EXISTS (SELECT 1 FROM MASKING_POLICY_TEMPLATES WHERE TEMPLATE_NAME='NULL_MASK' AND DATA_TYPE='TIMESTAMP_LTZ');
INSERT INTO MASKING_POLICY_TEMPLATES SELECT 'PARTIAL_EMAIL','STRING','Shows first char and domain, masks middle of email','CASE WHEN IS_ROLE_IN_SESSION(''<AUTHORIZED_ROLE>'') THEN val ELSE CONCAT(LEFT(val,1), ''****@'', SPLIT_PART(val, ''@'', 2)) END','j****@company.com',True WHERE NOT EXISTS (SELECT 1 FROM MASKING_POLICY_TEMPLATES WHERE TEMPLATE_NAME='PARTIAL_EMAIL' AND DATA_TYPE='STRING');
INSERT INTO MASKING_POLICY_TEMPLATES SELECT 'SHA256_HASH','STRING','SHA-256 hash for consistent pseudonymization','CASE WHEN IS_ROLE_IN_SESSION(''<AUTHORIZED_ROLE>'') THEN val ELSE SHA2(val, 256) END','(SHA-256 hash)',True WHERE NOT EXISTS (SELECT 1 FROM MASKING_POLICY_TEMPLATES WHERE TEMPLATE_NAME='SHA256_HASH' AND DATA_TYPE='STRING');
