-- ============================================================
-- PRISM Deployment - Step 4: Seed Data
-- ============================================================

USE ROLE IDENTIFIER($PRISM_APP_ROLE);
USE SCHEMA IDENTIFIER($PRISM_SECURITY_DB || '.' || $PRISM_SECURITY_SCHEMA);

-- Environments

-- Access Profiles (8 profiles)
  SELECT 'OWN','OWN_AR','Object Ownership — auto-transferred via FUTURE OWNERSHIP grants. System role only, not assigned to humans directly.',0,NULL,True,True,'ALL+FUTURE','DATABASE+SCHEMA'
  WHERE NOT EXISTS (SELECT 1 FROM ACCESS_PROFILES WHERE ACCESS_CODE='OWN');
  SELECT 'DBA','DBA_AR','Database Administration — ALL PRIVILEGES except OWNERSHIP. For database administrators.',1,'OWN',False,True,'ALL','DATABASE'
  WHERE NOT EXISTS (SELECT 1 FROM ACCESS_PROFILES WHERE ACCESS_CODE='DBA');
  SELECT 'FULL','FULL_AR','Full Access — CREATE objects, schema management, full usage. For lead developers and schema architects.',2,'DBA',False,True,'ALL+FUTURE','DATABASE+SCHEMA'
  WHERE NOT EXISTS (SELECT 1 FROM ACCESS_PROFILES WHERE ACCESS_CODE='FULL');
  SELECT 'RW','RW_AR','Read-Write — DML operations (INSERT, UPDATE, DELETE, TRUNCATE) plus stage read/write. For data engineers and ETL.',3,'FULL',False,True,'ALL+FUTURE','DATABASE+SCHEMA'
  WHERE NOT EXISTS (SELECT 1 FROM ACCESS_PROFILES WHERE ACCESS_CODE='RW');
  SELECT 'DO','DO_AR','DevOps — OPERATE and MONITOR on pipelines, tasks, dynamic tables, services. For platform engineers.',3,'FULL',False,True,'ALL+FUTURE','DATABASE+SCHEMA'
  WHERE NOT EXISTS (SELECT 1 FROM ACCESS_PROFILES WHERE ACCESS_CODE='DO');
  SELECT 'GOV','GOV_AR','Governance — CREATE and APPLY policies (masking, row access, projection, privacy, aggregation, join) and tags. For security and compliance teams.',3,'FULL',False,True,'ALL+FUTURE','DATABASE+SCHEMA'
  WHERE NOT EXISTS (SELECT 1 FROM ACCESS_PROFILES WHERE ACCESS_CODE='GOV');
  SELECT 'RO','RO_AR','Read-Only — SELECT and USAGE on all data objects. For analysts, testers, support, and reporting.',4,'RW',False,True,'ALL+FUTURE','DATABASE+SCHEMA'
  WHERE NOT EXISTS (SELECT 1 FROM ACCESS_PROFILES WHERE ACCESS_CODE='RO');
  SELECT 'SVC','SVC_AR','Service/AI Consumer — USAGE on agents, Cortex search, ML models, Streamlit apps, workspaces. For AI/ML consumers and app users.',5,NULL,False,True,'ALL+FUTURE','DATABASE+SCHEMA'
  WHERE NOT EXISTS (SELECT 1 FROM ACCESS_PROFILES WHERE ACCESS_CODE='SVC');

-- Environment Role Metadata
  SELECT '<ENV>_SYSADMIN','SYSADMIN','Environment system admin. Owns all databases and schemas in this environment. Inherits OWN_AR database roles.',True,True,False,False,1,True
  WHERE NOT EXISTS (SELECT 1 FROM ENVIRONMENT_ROLE_METADATA WHERE ROLE_TEMPLATE='<ENV>_SYSADMIN');
  SELECT '<ENV>_USERADMIN','USERADMIN','Environment user admin. Owns all database roles and account-level functional/technical roles in this environment.',False,False,True,True,2,True
  WHERE NOT EXISTS (SELECT 1 FROM ENVIRONMENT_ROLE_METADATA WHERE ROLE_TEMPLATE='<ENV>_USERADMIN');
  SELECT '<ENV>_ADMIN','<ENV>_SYSADMIN','Environment day-to-day admin. Granted to human administrators for operational tasks. Child of ENV_SYSADMIN.',False,False,False,False,3,True
  WHERE NOT EXISTS (SELECT 1 FROM ENVIRONMENT_ROLE_METADATA WHERE ROLE_TEMPLATE='<ENV>_ADMIN');

