  WHERE NOT EXISTS (SELECT 1 FROM FUNCTIONAL_TECHNICAL_ROLE_METADATA WHERE FUNCTION_NAME='AI' AND ROLE_TYPE='Functional');
  WHERE NOT EXISTS (SELECT 1 FROM FUNCTIONAL_TECHNICAL_ROLE_METADATA WHERE FUNCTION_NAME='BUSINESS_ANALYST' AND ROLE_TYPE='Functional');
  WHERE NOT EXISTS (SELECT 1 FROM FUNCTIONAL_TECHNICAL_ROLE_METADATA WHERE FUNCTION_NAME='DATA_SCIENTIST' AND ROLE_TYPE='Functional');
