  WHERE NOT EXISTS (SELECT 1 FROM FUNCTIONAL_TECHNICAL_ROLE_METADATA WHERE FUNCTION_NAME='PROTOTYPING' AND ROLE_TYPE='Functional');
  WHERE NOT EXISTS (SELECT 1 FROM FUNCTIONAL_TECHNICAL_ROLE_METADATA WHERE FUNCTION_NAME='SUPPORT' AND ROLE_TYPE='Functional');
  WHERE NOT EXISTS (SELECT 1 FROM FUNCTIONAL_TECHNICAL_ROLE_METADATA WHERE FUNCTION_NAME='TESTER' AND ROLE_TYPE='Functional');
  WHERE NOT EXISTS (SELECT 1 FROM FUNCTIONAL_TECHNICAL_ROLE_METADATA WHERE FUNCTION_NAME='ANALYTICS' AND ROLE_TYPE='Technical');
  WHERE NOT EXISTS (SELECT 1 FROM FUNCTIONAL_TECHNICAL_ROLE_METADATA WHERE FUNCTION_NAME='DATALOADER' AND ROLE_TYPE='Technical');
